code = """import json

with open(locals()['var_function-call-16142873375800227589'], 'r') as f:
    valid_stocks = json.load(f)

# Sort
valid_stocks.sort(key=lambda x: x['Symbol'])

chunk_size = 70

def get_chunk_query(chunk_index):
    start = chunk_index * chunk_size
    end = start + chunk_size
    chunk_stocks = valid_stocks[start:end]
    
    queries = []
    for stock in chunk_stocks:
        sym = stock['Symbol']
        table_name = f'"{sym}"'
        # Optimized query
        q = f"SELECT '{sym}' as S, SUM(CASE WHEN Close>Open THEN 1 END) as U, SUM(CASE WHEN Close<Open THEN 1 END) as D FROM {table_name} WHERE Date LIKE '2017%'"
        queries.append(q)
    
    if not queries:
        return ""
    return " UNION ALL ".join(queries)

# Print chunk 1
print("__RESULT__:")
print(json.dumps(get_chunk_query(1)))"""

